        (
            "id2",
            "Edit",
            serde_json::json!({"file_path": "/tmp/b", "old_str": "x", "new_str": "y"}),
        ),
    ];
    let all_pure = tool_uses
        .iter()
        .all(|(_, name, _)| tool_effect(name) == ToolEffect::Pure);
    assert!(!all_pure, "mixed batch with Edit should not be all-pure");
}

